3_real_world_example.code:
console.log('Script Start');

// 1. Goes to Web API, then Task Queue
setTimeout(() => {
  console.log('Timeout 1 executed');
}, 0);

// 2. Goes to Web API, then Task Queue
setTimeout(() => {
  console.log('Timeout 2 executed');
}, 0);

console.log('Script End');

// Output:
// Script Start
// Script End
// Timeout 1 executed
// Timeout 2 executed

// Note: Between Timeout 1 and Timeout 2, the Event Loop checks 
// for microtasks and rendering updates.

